var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"우후후후......","JPN":"フフフフ……","ENG":"Hah hah hah...","TWN":"呵呵呵呵……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크하하하핫!!!","JPN":"クハハハハッ！！！","ENG":"Bwa hah hah hah!","TWN":"哇哈哈哈哈哈！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"빠샤-!","JPN":"うりゃーっ！","ENG":"Kapow!","TWN":"喝啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 이제 겨우 흥이 오르던 참인데 벌써 자빠지다니......","JPN":"ちぇ、やっと盛り上がってきたところなのに、もう倒れちまうのかよ……","ENG":"No! I was just warming up, and they're already all down.","TWN":"啊，我才剛興奮起來，結果這麼快就不行了啊……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"침식체란 것들은 생존본능이 인간보다 약하다니까?","JPN":"侵食体ってのは、人間より生存本能がないんだな。","ENG":"These C.O.s just don't have the will to struggle, like humans.","TWN":"侵蝕體的生存本能比人類還弱嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"침식체들이 원래 이렇게 약한 존재였나......?","JPN":"侵食体って元々こんなに弱いものでしたか……？","ENG":"I didn't know C.O.s were so weak...","TWN":"還是侵蝕體本來就是弱小的存在……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 이런 실례. 동생이 사냥에 너무 심취한 것 같군요.","JPN":"フフ、これは失礼。妹が狩りに夢中になっていたようです。","ENG":"Hah hah. My apologies. My little sister may have gotten carried away with hunting.","TWN":"呵呵，失禮了。我妹妹好像太過投入狩獵了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"어쨌든 이 정도면 제물은 충분히 모인 것 같네요.","JPN":"とにかく、供え物は十分揃いましたね。","ENG":"Anyway, this should be enough for the offerings.","TWN":"不管怎樣，這樣祭品應該足夠了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇죠, 주인님?","JPN":"そうでしょう、ご主人様？","ENG":"Isn't that right, Mistress?","TWN":"您說是吧，主人？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"하암~ 벌써 끝났느냐?","JPN":"ふああ～もう終わりか？","ENG":"*Yawn* Are you done already?","TWN":"哈啊～這麼快就結束了啊？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"그럼 이 몸이 나설 차례로군.","JPN":"それじゃ、妾の出番だな。","ENG":"Then, it's time for me to step in.","TWN":"那就輪到我了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저기...... 그런데 정말 이런 게 운명의 상대를 찾는데 도움이 될까요?","JPN":"あの……ところで、本当にこんなことが運命の相手を探すのに役立つんですか？","ENG":"Excuse me, but can this really help me find my soul mate?","TWN":"那個……這樣真的能幫我找到命運之人嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"거 참 음침한 외모만큼이나 믿음이 부족한 처녀로구나.","JPN":"まったく、陰気な乙女じゃな。","ENG":"You're as suspicious as you are gloomy.","TWN":"真是個外表陰沉又多疑的女孩啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"도움이 안 되면 뭣 하러 직접 여기까지 나오는 수고를 하겠느냐?","JPN":"役に立たないというなら、何のために妾が直接出向いたと思っておるのじゃ。","ENG":"I wouldn't have come all the way here if it didn't help.","TWN":"如果沒有用，我又何必大老遠地跑來這裡？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"잔말 말고 네 머리카락이나 세 가닥 뽑아서 마법진 안에 놓아라.","JPN":"つまらないことを言ってないで、其方の髪を三本取って魔法陣の中に置け。","ENG":"Just be quiet and place three strands of your hair inside the pentacle.","TWN":"別說那些有的沒的了，拔三根頭髮，放進這個魔法陣裡。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"네? ......네.","JPN":"え？　……はい。","ENG":"Sorry? O-okay.","TWN":"咦？……是。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"이제 네가 원하는 상대를 말해보거라. 자세할수록 찾을 확률이 높아지겠지.","JPN":"今から其方が望む相手を言ってみるがよい。詳細であるほど見つける確率が高くなるであろう。","ENG":"Now, tell us about the one you want. The more descriptive, the better.","TWN":"告訴我妳正在找的對象是什麼樣子，越是具體，找到的機率就越高。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아......","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"탄탄하게 다져진 몸매에, 키는 저보다 크고, 겉은 도도하고 세련되면서도 내 사람에겐 한없이 상냥한...... 그런 멋진 사람이었으면 좋겠어요.","JPN":"がっちりした体つきに、私より背が高くて、見た目はおしゃれでクールですが、周りの人にはとことん優しい……そんな素敵な人がいいです。","ENG":"A strong, fit body. Taller than I am. Looks aloof and unapproachable on the outside, but gentle and selfless on the inside, especially when it comes to me. I want someone so nice.","TWN":"我希望是一個……身材好，身高比我高，外表看起來孤傲高尚，但對自己的人非常溫柔……那樣優秀的人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"아, 물론 사회적으로도 어느 정도 성공해서 인정받는 사람이라야 하고요.","JPN":"あ、もちろん社会的に成功してある程度の地位があることも大事です。","ENG":"Oh, and socially successful as well.","TWN":"啊，當然，他還得是被社會承認的成功人士。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"보통은 날 좋아해주기만 하면 아무것도 필요 없어요, 정도의 대사가 나와야 하는데......","JPN":"普通、自分を好きになってくれさえすれば他に何もいらない、くらいのセリフが出るところじゃが……","ENG":"I expected to hear \\"I just want someone who wants to love me.\\"","TWN":"通常不是該說“只要是真心愛我，其他怎麼樣都無所謂”之類的台詞嗎……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"역시 현실은 드라마보다 더 현실적이군,","JPN":"やはり現実は、ドラマよりもっと現実的じゃな。","ENG":"Life is more realistic than TV shows.","TWN":"果然現實比電視劇更現實。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"흥~ 좋다. 나도 뭐가 튀어나올지 궁금해지는걸?","JPN":"ふ～ん、まぁ、いい。妾も何が出てくるのか気になるのじゃ。","ENG":"Hm, okay. Now, I also want to know who your soul mate is.","TWN":"哼～算了，我也很好奇會出現什麼東西。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"어디...... 네 단짝은 어떻게 생겼을지, 한 번 문을 열어보자꾸나.","JPN":"どれ……其方の相棒はどんな姿なのか、一度扉を開けてみようじゃないか。","ENG":"Alright, let's open the door and see what your soul mate looks like.","TWN":"那麼……妳的理想對象是什麼樣子，我們得打開門才會知道。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"꿀꺽......","JPN":"ごくり……","ENG":"*Gulp*","TWN":"吞口水……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"아야야...... 아파라.","JPN":"いたたっ……痛いっ。","ENG":"Ow, ow... That hurts...","TWN":"哎呀呀……好痛。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"어라? 여긴 어디죠?","JPN":"あれ？　ここはどこですか？","ENG":"Err? Where am I?","TWN":"咦？這是什麼地方？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};